import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import * as Stomp from 'stompjs';
import * as SockJS from 'sockjs-client';

@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  private apiUrl = 'http://localhost:8080/api/notifications';
  private stompClient: any;

  constructor(private http: HttpClient) {}

  // Lấy danh sách thông báo
  getNotifications(userId: number, role: string): Observable<any[]> {
    return this.http.get<any[]>(`${this.apiUrl}/${userId}/${role}`);
  }

  // Đánh dấu đã đọc
  markAsRead(notificationId: number): Observable<void> {
    return this.http.post<void>(`${this.apiUrl}/mark-read/${notificationId}`, {});
  }

  // Kết nối WebSocket
  connectWebSocket(userId: number, callback: (notification: any) => void) {
    const socket = new SockJS('http://localhost:8080/ws');
    this.stompClient = Stomp.over(socket);
    this.stompClient.connect({}, () => {
      this.stompClient.subscribe(`/user/${userId}/queue/notifications`, (message: any) => {
        callback(JSON.parse(message.body));
      });
    });
  }

  disconnectWebSocket() {
    if (this.stompClient) {
      this.stompClient.disconnect();
    }
  }
}
